# Search helper using DuckDuckGo HTML
import html
import urllib.request
headers = { 'User-Agent': 'Mozilla/5.0' }

def search_urls(query):
    q = urllib.parse.urlencode({'q': query})
    url = 'https://duckduckgo.com/html/?' + q
    req = urllib.request.Request(url, headers=headers)
    with urllib.request.urlopen(req, timeout=15) as resp:
        data = resp.read().decode('utf-8', 'ignore')
    # Extract result links
    urls = []
    for m in re.finditer(r'<a[^>]+class="result__a"[^>]+href="([^"]+)"', data):
        href = html.unescape(m.group(1))
        # DuckDuckGo may wrap in /l/?kh=-1&uddg=encoded
        if 'uddg=' in href:
            try:
                parsed = urllib.parse.urlparse(href)
                qs = urllib.parse.parse_qs(parsed.query)
                if 'uddg' in qs:
                    href = urllib.parse.unquote(qs['uddg'][0])
            except Exception:
                pass
        urls.append(href)
    return urls

def pick_official(title):
    # Try to find GitHub/GitLab repo first
    queries = [f"{title} official code github", f"{title} github", f"{title} code"]
    seen = set()
    candidates = []
    for q in queries:
        try:
            for u in search_urls(q):
                if u in seen: continue
                seen.add(u)
                if any(host in u for host in ['github.com', 'gitlab.com', 'bitbucket.org', 'huggingface.co']):
                    # Filter for repo-like URLs (github.com/org/repo)
                    if 'github.com' in u:
                        parts = urllib.parse.urlparse(u).path.strip('/').split('/')
                        if len(parts) >= 2:
                            u = f"https://github.com/{parts[0]}/{parts[1]}"
                    candidates.append(u)
                # Also consider project pages from labs/universities
                elif any(k in u for k in ['.edu', 'research.google', 'facebook.ai', 'openai.com', 'deepmind.com', 'meta.com']):
                    candidates.append(u)
        except Exception:
            continue
        if candidates:
            break
    # Prefer GitHub repos
    gh = [c for c in candidates if 'github.com' in c]
    if gh:
        # De-dup and return first
        seen2 = []
        for g in gh:
            if g not in seen2:
                seen2.append(g)
        return seen2[0]
    # Fallback
    return candidates[0] if candidates else ''

