API_SEARCH = 'https://api.github.com/search/repositories?q={q}&sort=stars&order=desc&per_page=10'
API_README = 'https://api.github.com/repos/{owner}/{repo}/readme'

def gh_search_repos(title):
    # Build query terms: tokens length>=3
    toks = [w.lower() for w in re.findall(r'[A-Za-z0-9]+', title) if len(w) >= 3]
    # Deduplicate while preserving order
    used = []
    for t in toks:
        if t not in used:
            used.append(t)
    query = '+'.join(used) + '+in:name,description,readme'
    url = API_SEARCH.format(q=urllib.parse.quote(query))
    req = urllib.request.Request(url, headers=headers)
    with urllib.request.urlopen(req, timeout=15) as resp:
        data = resp.read().decode('utf-8', 'ignore')
    import json as _json
    j = _json.loads(data)
    return j.get('items', [])

def fetch_readme_text(owner, repo):
    url = API_README.format(owner=owner, repo=repo)
    req = urllib.request.Request(url, headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=15) as resp:
            if resp.getcode() == 200:
                import json as _json
                j = _json.loads(resp.read().decode('utf-8', 'ignore'))
                if 'content' in j and j.get('encoding') == 'base64':
                    return base64.b64decode(j['content']).decode('utf-8', 'ignore')
    except Exception:
        return ''
    return ''

