    owner = repo.get('owner', {}).get('login', '')
    name = repo.get('name', '') or ''
    desc = (repo.get('description') or '').lower()
    if owner in preferred_orgs:
        score += 3
    # Name overlap
    toks = [w for w in re.findall(r'[A-Za-z0-9]+', title.lower()) if len(w) >= 3]
