def gh_search_html(query, max_urls=20):
    q = urllib.parse.quote(query)
    url = f'https://github.com/search?q={q}&type=repositories&s=stars'
    req = urllib.request.Request(url, headers=headers)
    with urllib.request.urlopen(req, timeout=20) as resp:
        data = resp.read().decode('utf-8', 'ignore')
    # Extract repo hrefs like href="/owner/repo"
    urls = []
    for m in re.finditer(r'href="/([A-Za-z0-9_.-]+)/([A-Za-z0-9_.-]+)"', data):
