    # Use HEAD to default branch
    raw = f'https://raw.githubusercontent.com/{owner}/{repo}/HEAD/README.md'
    try:
        req = urllib.request.Request(raw, headers=headers)
        with urllib.request.urlopen(req, timeout=15) as resp:
