    if not owner or not repo:
        return 0
    if owner in preferred_orgs:
        score += 3
    toks = [w for w in re.findall(r'[A-Za-z0-9]+', title.lower()) if len(w) >= 3]
    name_overlap = sum(1 for w in toks if w in repo.lower())
    if name_overlap >= 2:
        score += 2
    # README content
    readme = fetch_readme(owner, repo)
    if readme:
